insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'If A # B means A x B + 3, find 4 # 5.', 'यदि A # B का अर्थ A x B + 3 है, तो 4 # 5 ज्ञात कीजिए।', '4 # 5 = 4 x 5 + 3 = 23. Therefore, answer = 23.', 'For coded mathematical operations, replace the symbol with its defined operation exactly and follow the stated order. Final answer is 23.', '4 # 5 = 4 x 5 + 3 = 23। अतः answer = 23।', 'Coded mathematical operations में symbol को exact defined operation से replace करें और stated order follow करें। Final answer 23 है।', 'EASY', array['reasoning','mathematical-operations']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
