insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'If A # B means A x B + 7, find 16 # 4.', 'यदि A # B का अर्थ A x B + 7 है, तो 16 # 4 ज्ञात कीजिए।', '16 # 4 = 16 x 4 + 7 = 71. Therefore, answer = 71.', 'For coded mathematical operations, replace the symbol with its defined operation exactly and follow the stated order. Final answer is 71.', '16 # 4 = 16 x 4 + 7 = 71। अतः answer = 71।', 'Coded mathematical operations में symbol को exact defined operation से replace करें और stated order follow करें। Final answer 71 है।', 'MEDIUM', array['reasoning','mathematical-operations']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
