insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '176', '176', false, 'Added 7 to B before multiplication: 16 x (4+7).', '7 को B में add करके multiplication किया: 16 x (4+7)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '57', '57', false, 'Subtracted 7 after multiplication instead of adding it.', 'Multiplication के बाद 7 add करने की जगह subtract कर दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'Data Sufficiency: Find y. Statement I: x + y = 12. Statement II: x = 8.', 'Data Sufficiency: y ज्ञात करें। Statement I: x + y = 12. Statement II: x = 8.', 'Together: y = 12 - 8 = 4. Therefore, answer = Both statements together are sufficient.', 'Data sufficiency asks whether the data can uniquely answer the question, not whether the final answer is immediately written in one statement. Final answer is Both statements together are sufficient.', 'Together: y = 12 - 8 = 4। अतः answer = Both statements together are sufficient।', 'Data sufficiency में पूछा जाता है कि data uniquely answer दे सकता है या नहीं, final answer statement में directly लिखा है या नहीं। Final answer Both statements together are sufficient है।', 'MEDIUM', array['reasoning','data-sufficiency']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Statement I alone is sufficient', 'Statement I alone is sufficient', false, 'Statement I gives only x+y=12; y cannot be fixed without x.', 'Statement I सिर्फ x+y=12 देता है; x के बिना y fixed नहीं होता।');
