insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Statement II alone is sufficient', 'Statement II alone is sufficient', false, 'Statement II gives x=26 but says nothing about y by itself.', 'Statement II x=26 देता है पर y के बारे में अकेले कुछ नहीं बताता।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both statements together are sufficient', 'Both statements together are sufficient', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither statement is sufficient', 'Neither statement is sufficient', false, 'Missed that combining x+y=35 with x=26 gives y=9.', 'यह miss किया कि x+y=35 और x=26 combine करने पर y=9 मिलता है।');
